        public XmlDocument GenerateAuthnRequest(string issuer, string destination, string assertionConsumerServiceUrl)
        {
            var id = "_" + Guid.NewGuid().ToString("N");
            var issueInstant = DateTime.UtcNow.ToString("yyyy-MM-ddTHH:mm:ssZ");

            var doc = new XmlDocument();
            doc.PreserveWhitespace = true;

            var declaration = doc.CreateXmlDeclaration("1.0", "UTF-8", null);
            doc.AppendChild(declaration);

            var authnRequest = doc.CreateElement("samlp", "AuthnRequest", SamlProtocolNamespace);
            authnRequest.SetAttribute("xmlns:saml", SamlAssertionNamespace);
            authnRequest.SetAttribute("ID", id);
            authnRequest.SetAttribute("Version", "2.0");
            authnRequest.SetAttribute("IssueInstant", issueInstant);
            authnRequest.SetAttribute("Destination", destination);
            authnRequest.SetAttribute("AssertionConsumerServiceURL", assertionConsumerServiceUrl);
            authnRequest.SetAttribute("ProtocolBinding", "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST");
            doc.AppendChild(authnRequest);

            var issuerElement = doc.CreateElement("saml", "Issuer", SamlAssertionNamespace);
            issuerElement.InnerText = issuer;
            authnRequest.AppendChild(issuerElement);

            var nameIdPolicy = doc.CreateElement("samlp", "NameIDPolicy", SamlProtocolNamespace);
            nameIdPolicy.SetAttribute("Format", "urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress");
            nameIdPolicy.SetAttribute("AllowCreate", "true");
            authnRequest.AppendChild(nameIdPolicy);

            var requestedAuthnContext = doc.CreateElement("samlp", "RequestedAuthnContext", SamlProtocolNamespace);
            requestedAuthnContext.SetAttribute("Comparison", "exact");
            authnRequest.AppendChild(requestedAuthnContext);

            var authnContextClassRef = doc.CreateElement("saml", "AuthnContextClassRef", SamlAssertionNamespace);
            authnContextClassRef.InnerText = "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport";
            requestedAuthnContext.AppendChild(authnContextClassRef);

            var conditions = doc.CreateElement("samlp", "Conditions", SamlProtocolNamespace);
            conditions.SetAttribute("NotBefore", issueInstant);
            conditions.SetAttribute("NotOnOrAfter", DateTime.UtcNow.AddMinutes(5).ToString("yyyy-MM-ddTHH:mm:ssZ"));
            authnRequest.AppendChild(conditions);

            return doc;
        }

