        public XmlDocument SignXmlDocument(XmlDocument doc, X509Certificate2 certificate)
        {
            var signedXml = new SignedXml(doc);

#pragma warning disable SYSLIB0045
            var rsaKey = certificate.GetRSAPrivateKey();
#pragma warning restore SYSLIB0045

            if (rsaKey == null)
                throw new InvalidOperationException("Certificate does not contain an RSA private key.");

            signedXml.SigningKey = rsaKey;

            // Use RSA-SHA1 for legacy system compatibility
#pragma warning disable SYSLIB0021
            signedXml.SignedInfo.SignatureMethod = SignedXml.XmlDsigRSASHA1Url;
#pragma warning restore SYSLIB0021

            var reference = new Reference("");
            reference.AddTransform(new XmlDsigEnvelopedSignatureTransform());
            reference.AddTransform(new XmlDsigExcC14NTransform());

            // Use SHA1 digest for legacy compatibility
#pragma warning disable SYSLIB0021
            reference.DigestMethod = SignedXml.XmlDsigSHA1Url;
#pragma warning restore SYSLIB0021

            signedXml.AddReference(reference);

            var keyInfo = new KeyInfo();
            var keyInfoData = new KeyInfoX509Data(certificate);
            keyInfo.AddClause(keyInfoData);
            signedXml.KeyInfo = keyInfo;

            signedXml.ComputeSignature();

            var signatureElement = signedXml.GetXml();

            var rootElement = doc.DocumentElement;
            if (rootElement != null)
            {
                // Insert signature after Issuer element if present, otherwise append
                var nsMgr = new XmlNamespaceManager(doc.NameTable);
                nsMgr.AddNamespace("saml", SamlAssertionNamespace);
                var issuerNode = rootElement.SelectSingleNode("saml:Issuer", nsMgr);
                if (issuerNode != null && issuerNode.NextSibling != null)
                {
                    rootElement.InsertAfter(doc.ImportNode(signatureElement, true), issuerNode);
                }
                else if (issuerNode != null)
                {
                    rootElement.AppendChild(doc.ImportNode(signatureElement, true));
                }
                else
                {
                    rootElement.PrependChild(doc.ImportNode(signatureElement, true));
                }
            }

            return doc;
        }
