    public class SamlEncryptionService
    {
        private const string SamlAssertionNamespace = "urn:oasis:names:tc:SAML:2.0:assertion";
        private const string XmlEncNamespace = "http://www.w3.org/2001/04/xmlenc#";

        public XmlDocument EncryptSensitiveAttributes(XmlDocument doc, X509Certificate2 encryptionCertificate)
        {
            var clonedDoc = new XmlDocument();
            clonedDoc.PreserveWhitespace = true;
            clonedDoc.LoadXml(doc.OuterXml);

            var nsMgr = new XmlNamespaceManager(clonedDoc.NameTable);
            nsMgr.AddNamespace("saml", SamlAssertionNamespace);

            var sensitiveAttributes = clonedDoc.SelectNodes("//saml:Attribute[@Sensitive='true']", nsMgr);

            if (sensitiveAttributes != null)
            {
                foreach (XmlElement attrElement in sensitiveAttributes)
                {
                    EncryptElement(clonedDoc, attrElement, encryptionCertificate);
                }
            }

            return clonedDoc;
        }

        private void EncryptElement(XmlDocument doc, XmlElement elementToEncrypt, X509Certificate2 certificate)
        {
            var rsaKey = certificate.GetRSAPublicKey();
            if (rsaKey == null)
                throw new InvalidOperationException("Certificate does not contain an RSA public key.");

            // Use TripleDES for legacy system compatibility
#pragma warning disable SYSLIB0022
            using var tripleDes = TripleDES.Create();
#pragma warning restore SYSLIB0022
            tripleDes.GenerateKey();
            tripleDes.GenerateIV();
            tripleDes.Mode = CipherMode.CBC;
            tripleDes.Padding = PaddingMode.PKCS7;

            var encryptedXml = new EncryptedXml();
            var encryptedData = new EncryptedData();
            encryptedData.Type = EncryptedXml.XmlEncElementUrl;
            encryptedData.EncryptionMethod = new EncryptionMethod(EncryptedXml.XmlEncTripleDESUrl);

            // Encrypt the element content
            byte[] plainText = Encoding.UTF8.GetBytes(elementToEncrypt.OuterXml);
            byte[] encryptedBytes;

            using (var encryptor = tripleDes.CreateEncryptor())
            using (var ms = new MemoryStream())
            {
                // Write IV first
                ms.Write(tripleDes.IV, 0, tripleDes.IV.Length);
                using (var cs = new CryptoStream(ms, encryptor, CryptoStreamMode.Write))
                {
                    cs.Write(plainText, 0, plainText.Length);
                    cs.FlushFinalBlock();
                }
                encryptedBytes = ms.ToArray();
            }

            encryptedData.CipherData = new CipherData(encryptedBytes);

            // Encrypt the symmetric key with RSA
            var encryptedKey = new EncryptedKey();
            byte[] encryptedKeyBytes = rsaKey.Encrypt(tripleDes.Key, RSAEncryptionPadding.OaepSHA1);
            encryptedKey.CipherData = new CipherData(encryptedKeyBytes);
            encryptedKey.EncryptionMethod = new EncryptionMethod(EncryptedXml.XmlEncRSAOAEPUrl);

            var keyInfo = new KeyInfo();
            keyInfo.AddClause(new KeyInfoX509Data(certificate));
            encryptedKey.KeyInfo = keyInfo;

            encryptedData.KeyInfo = new KeyInfo();
            encryptedData.KeyInfo.AddClause(new KeyInfoEncryptedKey(encryptedKey));

            // Replace the element with the encrypted version
            var encryptedElement = encryptedData.GetXml();
            var importedNode = doc.ImportNode(encryptedElement, true);

            if (elementToEncrypt.ParentNode != null)
            {
                elementToEncrypt.ParentNode.ReplaceChild(importedNode, elementToEncrypt);
            }
        }

        public XmlDocument DecryptSensitiveAttributes(XmlDocument encryptedDoc, X509Certificate2 decryptionCertificate)
        {
            var clonedDoc = new XmlDocument();
            clonedDoc.PreserveWhitespace = true;
            clonedDoc.LoadXml(encryptedDoc.OuterXml);

            var rsaKey = decryptionCertificate.GetRSAPrivateKey();
            if (rsaKey == null)
                throw new InvalidOperationException("Certificate does not contain an RSA private key.");

            var nsMgr = new XmlNamespaceManager(clonedDoc.NameTable);
            nsMgr.AddNamespace("xenc", XmlEncNamespace);

            var encryptedDataNodes = clonedDoc.SelectNodes("//xenc:EncryptedData", nsMgr);
            if (encryptedDataNodes != null)
            {
                foreach (XmlElement encDataElement in encryptedDataNodes)
                {
                    var encryptedData = new EncryptedData();
                    encryptedData.LoadXml(encDataElement);

                    // Extract encrypted key
                    EncryptedKey? encryptedKey = null;
                    foreach (KeyInfoClause clause in encryptedData.KeyInfo)
                    {
                        if (clause is KeyInfoEncryptedKey keyInfoEncKey)
                        {
                            encryptedKey = keyInfoEncKey.EncryptedKey;
                            break;
                        }
                    }

                    if (encryptedKey == null)
                        throw new InvalidOperationException("Encrypted key not found in the encrypted data.");

                    byte[] decryptedKeyBytes = rsaKey.Decrypt(encryptedKey.CipherData.CipherValue, RSAEncryptionPadding.OaepSHA1);

#pragma warning disable SYSLIB0022
                    using var tripleDes = TripleDES.Create();
#pragma warning restore SYSLIB0022
                    tripleDes.Key = decryptedKeyBytes;
                    tripleDes.Mode = CipherMode.CBC;
                    tripleDes.Padding = PaddingMode.PKCS7;

                    byte[] cipherBytes = encryptedData.CipherData.CipherValue;

                    // Extract IV from the beginning of cipher bytes
                    byte[] iv = new byte[tripleDes.BlockSize / 8];
                    Array.Copy(cipherBytes, 0, iv, 0, iv.Length);
                    tripleDes.IV = iv;

                    byte[] actualCipherBytes = new byte[cipherBytes.Length - iv.Length];
                    Array.Copy(cipherBytes, iv.Length, actualCipherBytes, 0, actualCipherBytes.Length);

                    byte[] decryptedBytes;
                    using (var decryptor = tripleDes.CreateDecryptor())
                    using (var ms = new MemoryStream(actualCipherBytes))
                    using (var cs = new CryptoStream(ms, decryptor, CryptoStreamMode.Read))
                    using (var resultMs = new MemoryStream())
                    {
                        cs.CopyTo(resultMs);
                        decryptedBytes = resultMs.ToArray();
                    }

                    string decryptedXml = Encoding.UTF8.GetString(decryptedBytes);

                    var tempDoc = new XmlDocument();
                    tempDoc.LoadXml(decryptedXml);

                    var importedNode = clonedDoc.ImportNode(tempDoc.DocumentElement!, true);
                    encDataElement.ParentNode?.ReplaceChild(importedNode, encDataElement);
                }
            }

            return clonedDoc;
        }
    }

    public class CertificateManager
    {
        private X509Certificate2? _signingCertificate;
        private X509Certificate2? _encryptionCertificate;

        public X509Certificate2 GetSigningCertificate()
        {
            if (_signingCertificate == null)
            {
                _signingCertificate = GenerateSelfSignedCertificate("CN=SAML Signing Certificate, O=Enterprise SSO");
            }
            return _signingCertificate;
        }

        public X509Certificate2 GetEncryptionCertificate()
        {
            if (_encryptionCertificate == null)
            {
                _encryptionCertificate = GenerateSelfSignedCertificate("CN=SAML Encryption Certificate, O=Enterprise SSO");
            }
            return _encryptionCertificate;
        }

        private X509Certificate2 GenerateSelfSignedCertificate(string subjectName)
        {
            using var rsa = RSA.Create(2048);
            var request = new CertificateRequest(
                subjectName,
                rsa,
                HashAlgorithmName.SHA256,
                RSASignaturePadding.Pkcs1);

            request.CertificateExtensions.Add(
                new X509KeyUsageExtension(
                    X509KeyUsageFlags.DigitalSignature | X509KeyUsageFlags.KeyEncipherment | X509KeyUsageFlags.DataEncipherment,
                    critical: true));

            request.CertificateExtensions.Add(
                new X509BasicConstraintsExtension(false, false, 0, true));

            var certificate = request.CreateSelfSigned(
                DateTimeOffset.UtcNow.AddDays(-1),
                DateTimeOffset.UtcNow.AddYears(2));

            // Export and re-import to ensure private key is available on all platforms
            var pfxBytes = certificate.Export(X509ContentType.Pfx, "temp_password");
            return new X509Certificate2(pfxBytes, "temp_password",
                X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.Exportable);
        }

        public X509Certificate2 LoadCertificateFromFile(string pfxPath, string password)
        {
            return new X509Certificate2(pfxPath, password,
                X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.Exportable);
        }

        public X509Certificate2 LoadCertificateFromStore(string thumbprint, StoreLocation location = StoreLocation.LocalMachine)
        {
            using var store = new X509Store(StoreName.My, location);
            store.Open(OpenFlags.ReadOnly);
            var certs = store.Certificates.Find(X509FindType.FindByThumbprint, thumbprint, false);
            if (certs.Count == 0)
                throw new InvalidOperationException($"Certificate with thumbprint {thumbprint} not found.");
            return certs[0];
        }
    }
